import "core-js/modules/esnext.iterator.constructor.js";
import "core-js/modules/esnext.iterator.filter.js";
import "core-js/modules/esnext.iterator.map.js";
import API from "@/services/api";
import FormField from "@/components/FormField.vue";
import FormSection from "@/components/FormSection.vue";
import ProfileUploadSection from "@/components/ProfileUploadSection.vue";
const fieldClass = "w-full rounded-2xl border border-slate-200 bg-slate-50 px-4 py-3 outline-none transition focus:border-primary focus:bg-white focus:ring-4 focus:ring-primary/10";
const selectOptions = {
  country: ["Philippines", "United States", "Canada", "Australia", "Japan", "South Korea", "China", "India", "Singapore", "Malaysia", "Indonesia", "Thailand", "Vietnam", "United Kingdom", "France", "Germany", "Italy", "Spain", "United Arab Emirates", "Saudi Arabia"],
  sex: ["Male", "Female"],
  civilStatus: ["Single", "Married", "Widowed", "Separated"],
  nationality: ["Filipino", "American", "Canadian", "Australian", "Japanese", "Korean", "Chinese", "Indian", "Singaporean", "Malaysian", "Indonesian", "Thai", "Vietnamese", "British", "French", "German", "Italian", "Spanish", "Emirati", "Saudi"],
  bloodType: ["A+", "A-", "B+", "B-", "AB+", "AB-", "O+", "O-"],
  disposition: ["For processing", "Under investigation", "Referred", "Released", "Detained", "Deported", "Closed"],
  visaStatus: ["Valid", "Expired", "Cancelled", "Pending", "Overstayed", "Not applicable"],
  eyeColor: ["Brown", "Black", "Hazel", "Blue", "Green", "Gray"],
  hairColor: ["Black", "Brown", "Blonde", "Gray", "White", "Red", "Bald"],
  complexion: ["Fair", "Light", "Medium", "Olive", "Morena", "Dark"]
};
function createInitialForm() {
  return {
    personalInformation: {
      firstName: "",
      middleName: "",
      alias: "",
      lastName: "",
      sex: "",
      civilStatus: "",
      birthDate: "",
      contactNumber: "",
      emailAddress: "",
      nationality: "",
      country: "",
      address: ""
    },
    operationDetails: {
      operationName: "",
      operationAddress: "",
      operationDate: "",
      disposition: "",
      visaStatus: "",
      remarks: "",
      actions: ""
    },
    biometrics: {
      heightCm: "",
      weightKg: "",
      bloodType: "",
      eyeColor: "",
      hairColor: "",
      complexion: "",
      distinguishingMarks: "",
      fingerprintCode: ""
    },
    profilePhoto: {
      fileName: "",
      mimeType: "",
      size: 0,
      dataUrl: ""
    }
  };
}
export default {
  name: "RegisterRecord",
  components: {
    FormField,
    FormSection,
    ProfileUploadSection
  },
  data() {
    return {
      form: createInitialForm(),
      selectedRecordId: "",
      isSubmitting: false,
      profilePreview: "",
      people: [],
      peopleSearch: "",
      isLoadingPeople: false,
      peopleError: "",
      fieldClass,
      selectOptions,
      message: {
        type: "",
        text: ""
      }
    };
  },
  computed: {
    isEditing() {
      return Boolean(this.selectedRecordId);
    },
    filteredPeople() {
      const keyword = this.peopleSearch.toLowerCase();
      if (!keyword) {
        return this.people;
      }
      return this.people.filter(person => {
        const info = person.personalInformation || {};
        const haystack = [info.firstName, info.middleName, info.lastName, info.alias, info.nationality, info.country].filter(Boolean).join(" ").toLowerCase();
        return haystack.includes(keyword);
      });
    },
    profileSummary() {
      if (!this.form.profilePhoto.fileName) {
        return "No image selected yet.";
      }
      const sizeInKb = this.form.profilePhoto.size ? `${(this.form.profilePhoto.size / 1024).toFixed(1)} KB` : "Unknown size";
      return `${this.form.profilePhoto.mimeType || "Image"} | ${sizeInKb}`;
    }
  },
  methods: {
    async loadPeople() {
      this.isLoadingPeople = true;
      this.peopleError = "";
      try {
        const response = await API.get("/records");
        this.people = Array.isArray(response.data) ? response.data : [];
      } catch (error) {
        this.peopleError = error.response?.data?.message || "Unable to load registered people right now.";
      } finally {
        this.isLoadingPeople = false;
      }
    },
    formatPersonName(person) {
      const info = person.personalInformation || {};
      return [info.firstName, info.middleName, info.lastName].filter(Boolean).join(" ");
    },
    getPersonInitials(person) {
      const info = person.personalInformation || {};
      return [info.firstName, info.lastName].filter(Boolean).map(value => value.charAt(0)).join("").slice(0, 2) || "NA";
    },
    formatPersonMeta(person) {
      const info = person.personalInformation || {};
      return [info.alias ? `Alias: ${info.alias}` : null, info.nationality || null, info.country || null].filter(Boolean).join(" | ");
    },
    createFormFromRecord(record) {
      return {
        personalInformation: {
          ...createInitialForm().personalInformation,
          ...(record.personalInformation || {})
        },
        operationDetails: {
          ...createInitialForm().operationDetails,
          ...(record.operationDetails || {})
        },
        biometrics: {
          ...createInitialForm().biometrics,
          ...(record.biometrics || {})
        },
        profilePhoto: {
          ...createInitialForm().profilePhoto,
          ...(record.profilePhoto || {})
        }
      };
    },
    selectPerson(person) {
      this.message = {
        type: "",
        text: ""
      };
      this.selectedRecordId = person._id;
      this.form = this.createFormFromRecord(person);
      this.profilePreview = person.profilePhoto?.dataUrl || "";
    },
    resetFormState() {
      this.selectedRecordId = "";
      this.form = createInitialForm();
      this.profilePreview = "";
      this.message = {
        type: "",
        text: ""
      };
    },
    async handleProfileUpload(event) {
      this.message = {
        type: "",
        text: ""
      };
      const [file] = event.target.files || [];
      if (!file) {
        this.form.profilePhoto = createInitialForm().profilePhoto;
        this.profilePreview = "";
        return;
      }
      if (file.size > 2 * 1024 * 1024) {
        this.message = {
          type: "error",
          text: "Please upload an image that is 2 MB or smaller."
        };
        event.target.value = "";
        return;
      }
      const dataUrl = await this.readFileAsDataUrl(file);
      this.form.profilePhoto = {
        fileName: file.name,
        mimeType: file.type,
        size: file.size,
        dataUrl
      };
      this.profilePreview = dataUrl;
    },
    readFileAsDataUrl(file) {
      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => resolve(reader.result);
        reader.onerror = () => reject(new Error("Unable to read the selected file."));
        reader.readAsDataURL(file);
      });
    },
    async handleSubmit() {
      this.message = {
        type: "",
        text: ""
      };
      if (!this.form.personalInformation.firstName || !this.form.personalInformation.lastName || !this.form.personalInformation.sex || !this.form.personalInformation.birthDate) {
        this.message = {
          type: "error",
          text: "First name, last name, sex, and birth date are required."
        };
        return;
      }
      this.isSubmitting = true;
      try {
        const response = this.isEditing ? await API.put(`/records/${this.selectedRecordId}`, this.form) : await API.post("/records", this.form);
        this.message = {
          type: "success",
          text: response.data.message || (this.isEditing ? "Registration updated successfully." : "Registration saved successfully.")
        };
        await this.loadPeople();
        if (this.isEditing && response.data.record) {
          this.selectPerson(response.data.record);
        } else {
          this.resetFormState();
        }
      } catch (error) {
        this.message = {
          type: "error",
          text: error.response?.data?.message || "Unable to save the registration right now."
        };
      } finally {
        this.isSubmitting = false;
      }
    }
  },
  mounted() {
    this.loadPeople();
  }
};
